params.script:
var rawData = $runner.getModuleResult("script_患者_連絡先");
var d = rawData ? String(rawData).replace(/[^0-9]/g, "") : "";
var res = "INVALID";

var mobilePattern = /^0(50|60|70|80|90)\d{8}$/;
var fixedPattern = /^0(?!(50|60|70|80|90))\d{9,10}$/;

if (d && (mobilePattern.test(d) || fixedPattern.test(d))) {
    var m = ["ぜろ", "いち", "に", "さん", "よん", "ご", "ろく", "なな", "はち", "きゅう"];
    
    // 全体を 75% の速度指定で囲みます
    var ssml = "<prosody rate='75%'>";
    
    for (var i = 0; i < d.length; i++) {
        var n = parseInt(d.charAt(i), 10);
        
        // 各数字の後に 100ms の極小の間を入れ、物理的に話速を落とします
        ssml += "<sub alias='" + m[n] + "'>" + d.charAt(i) + "</sub><break time='100ms'/>";

        // 区切り（の）のリズム制御
        var isPause = false;
        if (d.length == 11) { // 携帯・IP電話
            if (i == 2 || i == 6) isPause = true;
        } else if (d.length == 10) { // 固定電話
            var prefix2 = d.substring(0, 2);
            if (prefix2 == "03" || prefix2 == "06") {
                if (i == 1 || i == 5) isPause = true;
            } else {
                if (i == 2 || i == 5) isPause = true;
            }
        }

        if (isPause) {
            // 「の、」に 600ms の溜めを作り、メモを取りやすくします
            ssml += "の、<break time='600ms'/>";
        }
    }
    
    // 最後の番号を言い終わった後の「でよろしいですか？」への繋ぎ（1秒）
    ssml += "<break time='1000ms'/>";
    ssml += "</prosody>";
    res = ssml;
}

$runner.setResult(res);

